uint8_t Convert_Byte(uint8_t Data) 
{
	uint8_t Data1;
	Data1 = Data;
	Data = 0x00;

	for(int i = 0 ; i<(sizeof(uint8_t)*8/2) ; i++)
	{
		Data = Data | (Data1&(0X80>>i))>>(7-i*2);
		Data = Data | (Data1&(0X01<<i))<<(7-i*2);
	}

	return  Data;

}

